using System;

class Program {
    static void Main() {
        try {
            int[] arr = new int[3];
            arr[10] = 99; // IndexOutOfRangeException
        } catch (IndexOutOfRangeException ex) {
            Console.WriteLine($"Error: {ex.Message}");
        }
        Console.WriteLine("Program continues");
    }
}

using System;

class Program {
    static void Parse(string s) {
        try {
            int n = int.Parse(s);
            Console.WriteLine(100 / n);
        } catch (DivideByZeroException) {
            Console.WriteLine("Cannot divide by zero");
        } catch (FormatException) {
            Console.WriteLine($"'{s}' is not a number");
        } catch (Exception ex) {
            Console.WriteLine($"Unexpected: {ex.Message}");
        }
    }

    static void Main() {
        Parse("0");
        Parse("abc");
        Parse("5");
    }
}

using System;

class Program {
    static void Main() {
        Console.WriteLine("start");
        try {
            Console.WriteLine("in try");
            throw new Exception("oops");
        } catch (Exception ex) {
            Console.WriteLine($"caught: {ex.Message}");
        } finally {
            Console.WriteLine("finally always runs");
        }
        Console.WriteLine("end");
    }
}

using System;

static int Divide(int a, int b) {
    if (b == 0) throw new DivideByZeroException("denominator cannot be zero");
    return a / b;
}

class Program {
    static void Main() {
        try {
            Console.WriteLine(Divide(10, 2));
            Console.WriteLine(Divide(10, 0));
        } catch (DivideByZeroException ex) {
            Console.WriteLine(ex.Message);
        }
    }
}

using System;

class InsufficientFundsException : Exception {
    public decimal Amount { get; }
    public InsufficientFundsException(decimal amount)
        : base($"Insufficient funds: need {amount:C} more") {
        Amount = amount;
    }
}

class Account {
    public decimal Balance { get; private set; }
    public Account(decimal initial) { Balance = initial; }
    public void Withdraw(decimal amount) {
        if (amount > Balance)
            throw new InsufficientFundsException(amount - Balance);
        Balance -= amount;
    }
}

class Program {
    static void Main() {
        var acc = new Account(100);
        try { acc.Withdraw(150); }
        catch (InsufficientFundsException ex) {
            Console.WriteLine(ex.Message);
            Console.WriteLine($"Short by: {ex.Amount:C}");
        }
    }
}

using System;

class Program {
    static void Main() {
        for (int code = 400; code <= 404; code++) {
            try {
                throw new Exception($"HTTP {code}");
            } catch (Exception ex) when (ex.Message.Contains("404")) {
                Console.WriteLine($"Not Found: {ex.Message}");
            } catch (Exception ex) {
                Console.WriteLine($"Other error: {ex.Message}");
            }
        }
    }
}

using System;

static void Inner() { throw new InvalidOperationException("inner error"); }

static void Outer() {
    try { Inner(); }
    catch (Exception ex) {
        Console.WriteLine($"Outer caught: {ex.Message}");
        throw; // re-throw, preserving stack trace
    }
}

class Program {
    static void Main() {
        try { Outer(); }
        catch (Exception ex) {
            Console.WriteLine($"Main caught: {ex.Message}");
        }
    }
}

using System;

class Program {
    static void Main() {
        try {
            try {
                throw new InvalidOperationException("original");
            } catch (Exception inner) {
                throw new ApplicationException("wrapper", inner);
            }
        } catch (Exception ex) {
            Console.WriteLine(ex.Message);
            Console.WriteLine(ex.InnerException?.Message);
        }
    }
}
